import React, { useState } from 'react';
import { Archive, Search, Calendar, UserPlus, Trash2 } from 'lucide-react';
import { useApp, useAppActions } from '../context/AppContext';
import CalendarModal from './Calendar';
import '../styles/globals.css';

const Toolbar: React.FC = () => {
  const { state } = useApp();
  const { archiveItems, deleteItems, setSearch, setFilter, addToast } = useAppActions();
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);

  const handleArchive = () => {
    const itemsCount = state.selectedItems.length;
    archiveItems();

    // Mostrar Toast de sucesso
    addToast({
      type: 'success',
      title: state.language === 'pt' ? 'Itens arquivados' : 'Items archived',
      message: state.language === 'pt' 
        ? `${itemsCount} item(ns) foram arquivados com sucesso` 
        : `${itemsCount} item(s) archived successfully`,
      duration: 3000
    });
  };

  const handleDelete = () => {
    const itemsCount = state.selectedItems.length;
    deleteItems();

    // Mostrar Toast de sucesso
    addToast({
      type: 'success',
      title: state.language === 'pt' ? 'Itens excluídos' : 'Items deleted',
      message: state.language === 'pt' 
        ? `${itemsCount} item(ns) foram excluídos com sucesso` 
        : `${itemsCount} item(s) deleted successfully`,
      duration: 3000
    });
  };

  const hasSelection = state.selectedItems.length > 0;

  const handleSchedule = () => {
    setIsCalendarOpen(true);
  };

  return (
    <div 
      className="flex items-center justify-between p-4 border-b gap-4"
      style={{
        backgroundColor: 'var(--color-surface)',
        borderColor: 'var(--color-border)'
      }}
    >
      <div className="flex items-center gap-3 flex-1">
        {/* Campo de busca */}
        <div className="relative flex-1 max-w-md">
          <Search 
            size={18} 
            className="absolute left-3 top-1/2 transform -translate-y-1/2"
            style={{ color: 'var(--color-text-muted)' }}
          />
          <input
            type="text"
            placeholder="Buscar..."
            value={state.searchQuery}
            onChange={(e) => setSearch(e.target.value)}
            className="input pl-10"
            style={{
              backgroundColor: 'var(--color-background)',
              borderColor: 'var(--color-border)',
              color: 'var(--color-text-primary)'
            }}
          />
        </div>

        {/* Filtros */}
        <select
          value={state.filter}
          onChange={(e) => setFilter(e.target.value as 'all' | 'unread')}
          className="input"
          style={{
            backgroundColor: 'var(--color-background)',
            borderColor: 'var(--color-border)',
            color: 'var(--color-text-primary)'
          }}
        >
          <option value="all">Todos</option>
          <option value="unread">Não lidos</option>
        </select>
      </div>

      <div className="flex items-center gap-2">
        {/* Ações quando há seleção */}
        {hasSelection ? (
          <>
            <button
              onClick={handleArchive}
              className="btn btn-primary"
              title={`Arquivar ${state.selectedItems.length} item(ns)`}
            >
              <Archive size={16} />
              <span className="hide-mobile">Arquivar</span>
              <span 
                className="bg-blue-800 text-white text-xs px-2 py-1 rounded-full"
                style={{
                  backgroundColor: 'var(--color-primary-hover)',
                  minWidth: '1.5rem',
                  height: '1.5rem'
                }}
              >
                {state.selectedItems.length}
              </span>
            </button>

            <button className="btn btn-secondary">
              <UserPlus size={16} />
              <span className="hide-mobile">Atribuir</span>
            </button>

            <button onClick={handleSchedule} className="btn btn-secondary">
              <Calendar size={16} />
              <span className="hide-mobile">Agendar</span>
            </button>

            <button onClick={handleDelete} className="btn btn-secondary" style={{ color: 'var(--color-danger)' }}>
              <Trash2 size={16} />
              <span className="hide-mobile">Excluir</span>
            </button>
          </>
        ) : (
          <div 
            className="text-sm"
            style={{ color: 'var(--color-text-muted)' }}
          >
            Selecione itens para ações
          </div>
        )}
      </div>

      {/* Calendar Modal */}
      <CalendarModal 
        isOpen={isCalendarOpen} 
        onClose={() => setIsCalendarOpen(false)} 
      />
    </div>
  );
};

export default Toolbar;
